798edb5d-772d-40ac-8e88-c55213280a2a	aa64f3a5-bb5b-43f3-8cde-0f3fa55857bc	0	route-uploads	3d4fcee7-7b78-42a5-bac5-8293378a86b2/1772721796888-4590397f-a0a6-48af-a5cf-e6190671ac85.png	533	648	{"expiresAt": 1773327041529, "updatedAt": 1772722241529, "currentName": "", "currentGrade": "6A", "currentPoints": [], "completedRoutes": [{"id": "route-1772722113027-fe0jx4263", "name": "Sigue Respirando", "grade": "5A+", "points": [{"x": 0.285475499621703, "y": 0.7291667351479869}, {"x": 0.3180433715583735, "y": 0.5969073750734117}, {"x": 0.40271983859371613, "y": 0.5238166760848306}, {"x": 0.47219796539194625, "y": 0.44028444866930955}, {"x": 0.46351319954216763, "y": 0.36719374968072854}, {"x": 0.41574698736838434, "y": 0.35327171177814165}, {"x": 0.44180128491772064, "y": 0.20186954958750944}, {"x": 0.480882731241725, "y": 0.12703859586110514}, {"x": 0.5568744324272892, "y": 0.07483095372640436}, {"x": 0.5568744324272892, "y": 0.06961018951293432}], "climbType": "boulder", "imageWidth": 533, "description": "💀💀💀\\nBoulder muy técnico y alto, con una línea recta y sostenida\\nde movimientos precisos.\\n\\n A partir del cuarto agarre, es esencial trabajar\\ncorrectamente los pies: los agarres de manos sirven más\\npara equilibrar que para jalar.\\n\\n La línea se desarrolla en una pendiente positiva, donde la\\nclave está en la técnica de pies y control del cuerpo.\\n\\nTodos los agarres son buenos y sólidos, pero el\\ncompromiso aumenta con la altura.\\nAperturista: Cesar Montes\\nF.A: Cesar Montes", "imageHeight": 648, "sequenceOrder": 0}, {"id": "route-1772722227015-21oa2arzm", "name": "Adán", "grade": "6A", "points": [{"x": 0.10960899116368338, "y": 0.753617319525241}, {"x": 0.12914971432568553, "y": 0.6439812710423692}, {"x": 0.0900682680016811, "y": 0.5534880246755547}, {"x": 0.10960899116368338, "y": 0.4821375804247974}, {"x": 0.11612256555101745, "y": 0.38120280563104253}, {"x": 0.15520401187502186, "y": 0.2994108329533448}, {"x": 0.26159239353481156, "y": 0.271566757148171}, {"x": 0.37449434958193545, "y": 0.21935911501347025}, {"x": 0.3918638812814931, "y": 0.1462684160248892}, {"x": 0.3918638812814931, "y": 0.0958010286280118}], "climbType": "boulder", "imageWidth": 533, "description": "💀💀💀\\nBoulder de exposición media-alta, técnico y con secciones de precisión.\\n\\n Inicia en dos agarres muy buenos, para luego ir a un sloper con leve incut, donde el equilibrio y el uso de\\npies finos son fundamentales.\\n\\n Con la mano izquierda se trabaja una serie de laterales, hasta llegar a un crimp clave:\\n\\n en ese punto, la línea se divide — hacia la derecha continúa Adán, mientras que hacia la izquierda parte\\nEva.\\nAperturista: Lalo Esperón, Jorge Martínez y Beto Pacheco\\n\\nF.A: Beto Pacheco", "imageHeight": 648, "sequenceOrder": 1}], "currentClimbType": "boulder", "currentDescription": ""}	\N	\N	2026-03-05 14:43:24.306243+00	2026-03-10 13:24:33.434921+00	\N	supabase	route-uploads	3d4fcee7-7b78-42a5-bac5-8293378a86b2/1772721796888-4590397f-a0a6-48af-a5cf-e6190671ac85.png	\N	\N	{}	pending	\N	\N
